import { Vex } from '@vex_dev/sdk';
import { createMastraAgent } from 'mastra';

const vex = new Vex({
  projectId: 'your-project-id',
  apiKey: process.env.VEX_API_KEY!
});

const agent = createMastraAgent({
  workflow: {
    steps: [
      {
        name: 'analyzeCustomerData',
        handler: async (input, context) => {
          // Vex guardrail before workflow transition
          await vex.guard('workflow.validate-output', {
            tenantId: context.tenantId,
            workflowStep: 'analyzeCustomerData',
            inputData: input,
            rules: {
              schema: 'customerDataSchema',
              tenantIsolation: true,
              piiRedaction: 'required',
              dataResidency: context.region
