          });

          return result;
        }
      }
    ]
  }
});

import { Vex } from '@vex_dev/sdk';

const memoryGuardrail = async (query: string, tenantId: string, region: string) => {
  const validation = await vex.guard('memory.tenant-isolation', {
    tenantId,
    query,
    context: {
      knowledgeSource: 'mastra-memory',
      accessPattern: 'retrieval',
      dataResidency: region,
      sensitivity: 'high'
    },
    rules: {
      tenantIsolation: 'strict',
      staleContextBlock: true,
      crossRegionBlock: true,
      auditLog: 'full'
    }
  });

  if (!validation.pass) {
    throw new Error(`Memory access blocked: ${validation.reason}`);
  }

  return mastra.knowledge.retrieve(query, { tenantId });
};

