import { Vex } from '@vex_dev/sdk';

const auditMiddleware = async (agentAction: string, input: any, tenantId: string, metadata: any) => {
  const auditRecord = await vex.audit({
    eventType: `mastra.${agentAction}`,
    tenantId,
    timestamp: new Date().toISOString(),
    actor: 'ai-agent',
    actionDetails: {
      inputHash: await vex.hash(JSON.stringify(input)),
      workflowStep: metadata.step,
      toolCalls: metadata.tools || [],
      decisionPath: metadata.decisionPath
    },
    complianceContext: {
      soc2: true,
      gdpr: true,
      dataResidency: metadata.region,
      sensitivityLevel: 'enterprise'
    }
  });

  return {
    auditId: auditRecord.id,
    signature: auditRecord.signature
  };
};

// Wrap Mastra tool calls
const safeToolCall = async (toolName: string, params: any, tenantId: string) => {
  const audit = await auditMiddleware('tool-call', params, tenantId, {
    step: 'tool-execution',
    tools: [toolName]
  });

  try {
    const result = await mastra.tools[toolName](params);
    await auditMiddleware('tool-success', result, tenantId, {
      step: 'tool-complete',
      toolResult: true
    });
    return result;
  } catch (error) {
    await vex.audit('tool-failure', { ...audit, error: error.message });
    throw error;
  }
};
